const QUESTION_BANK: Record<string, Question[]> = {
  Mathematics: MATHEMATICS,
  'Use of English': ENGLISH,
  Physics: PHYSICS,
  Chemistry: CHEMISTRY,
  Biology: BIOLOGY,
  Economics: ECONOMICS,
  Commerce: COMMERCE,
  Accounting: ACCOUNTING,
  'Literature in English': LITERATURE,
  Government: GOVERNMENT,
  'Islamic Studies': ISLAMIC_STUDIES,
  CRS: CRS,
  Yoruba: YORUBA,
  Arabic: ARABIC,
  Listening: TOEFL_LISTENING,
  Reading: TOEFL_READING,
  Speaking: TOEFL_SPEAKING,
  Writing: TOEFL_WRITING,
}

export function getQuestions(subject: string): Question[] {
  const bank = QUESTION_BANK[subject]
  if (bank) return [...bank]
  return MATHEMATICS.map((q, i) => ({
    ...q,
    id: `${subject.slice(0, 3).toLowerCase()}${i}`,
    question: `[${subject}] ${q.question}`,
    subject: subject as Subject,
  }))
}
